 12	import useBootableVolumes from '@kubevirt-utils/resources/bootableresources/hooks/useBootableVolumes';
 13	import { useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 14	import { Bullseye, Card, Divider, Grid, GridItem, List } from '@patternfly/react-core';
 15	
 16	import AddBootableVolumeButton from './components/AddBootableVolumeButton/AddBootableVolumeButton';
 17	import BootableVolumeList from './components/BootableVolumeList/BootableVolumeList';
 18	import CreateFromInstanceTypeTitle from './components/CreateFromInstanceTypeTitle/CreateFromInstanceTypeTitle';
 19	import CreateVMFooter from './components/CreateVMFooter/CreateVMFooter';
 20	import SectionListItem from './components/SectionListItem/SectionListItem';
 21	import useInstanceTypesAndPreferences from './state/hooks/useInstanceTypesAndPreferences';
 22	import { useInstanceTypeVMStore } from './state/useInstanceTypeVMStore';
 23	import { INSTANCE_TYPES_SECTIONS } from './utils/constants';
 24	
 25	import './CreateFromInstanceType.scss';
 26	
 27	type CreateFromInstanceTypeProps = { currentTab: CREATE_VM_TAB };
 28	
 29	const CreateFromInstanceType: FC<CreateFromInstanceTypeProps> = ({ currentTab }) => {
 30	  const { t } = useKubevirtTranslation();
 31	  const sectionState = useState<INSTANCE_TYPES_SECTIONS>(INSTANCE_TYPES_SECTIONS.SELECT_VOLUME);
 32	
 33	  const { resetInstanceTypeVMState, setVMNamespaceTarget, volumeListNamespace } =
 34	    useInstanceTypeVMStore();
 35	  const bootableVolumesData = useBootableVolumes(volumeListNamespace);
 36	  const instanceTypesAndPreferencesData = useInstanceTypesAndPreferences();
 37	  const [activeNamespace] = useActiveNamespace();
 38	  const [authorizedSSHKeys, , loaded] = useKubevirtUserSettings('ssh');
 39	
 40	  useEffect(() => {
 41	    resetInstanceTypeVMState();
 42	  }, [resetInstanceTypeVMState]);
 43	
 44	  useEffect(() => {
 45	    const targetNS =
 46	      activeNamespace === ALL_NAMESPACES_SESSION_KEY ? DEFAULT_NAMESPACE : activeNamespace;
 47	    setVMNamespaceTarget(authorizedSSHKeys?.[targetNS], targetNS);
 48	  }, [activeNamespace, authorizedSSHKeys, setVMNamespaceTarget]);
 49	
 50	  const [favorites = [], updaterFavorites, loadedFavorites] =
 51	    useKubevirtUserSettings('favoriteBootableVolumes');
 52	
 53	  if (
 54	    !bootableVolumesData?.loaded ||
 55	    !instanceTypesAndPreferencesData?.loaded ||
 56	    !loaded ||
 57	    (!loadedFavorites && !favorites)
 58	  ) {
 59	    return (
 60	      <Bullseye className="create-vm-instance-type-section__page-loader">
 61	        <Loading />
 62	      </Bullseye>
 63	    );
 64	  }
 65	
 66	  return (
 67	    <>
 68	      <GuidedTour />
 69	      <Grid className="co-dashboard-body">
 70	        <GridItem>
 71	          <Card>
 72	            <List className="create-vm-instance-type-section__list" isPlain>
 73	              <SectionListItem
 74	                headerAction={
 75	                  <AddBootableVolumeButton loadError={instanceTypesAndPreferencesData.loadError} />
 76	                }
 77	                headerText={
 78	                  <CreateFromInstanceTypeTitle
 79	                    instanceTypesAndPreferencesData={instanceTypesAndPreferencesData}
 80	                  />
 81	                }
 82	                sectionKey={INSTANCE_TYPES_SECTIONS.SELECT_VOLUME}
 83	                sectionState={sectionState}
 84	              >
 85	                <BootableVolumeList
 86	                  bootableVolumesData={bootableVolumesData}
 87	                  currentTab={currentTab}
 88	                  displayShowAllButton
 89	                  favorites={[favorites as [], updaterFavorites]}
 90	                  preferencesData={instanceTypesAndPreferencesData.preferences}
 91	                />
 92	              </SectionListItem>
 93	
 94	              <Divider className="create-vm-instance-type-section__divider" />
 95	
 96	              <SectionListItem
 97	                headerText={t('Select InstanceType')}
 98	                sectionKey={INSTANCE_TYPES_SECTIONS.SELECT_INSTANCE_TYPE}
 99	                sectionState={sectionState}
100	              >
101	                <SelectInstanceTypeSection
102	                  instanceTypesAndPreferencesData={instanceTypesAndPreferencesData}
103	                />
104	              </SectionListItem>
105	
106	              <Divider className="create-vm-instance-type-section__divider" />
107	
108	              <SectionListItem
109	                headerText={t('VirtualMachine details')}
110	                sectionKey={INSTANCE_TYPES_SECTIONS.VM_DETAILS}
111	                sectionState={sectionState}
112	              >
113	                <VMDetailsSection
114	                  instanceTypesAndPreferencesData={instanceTypesAndPreferencesData}
115	                />
116	              </SectionListItem>
117	            </List>
118	          </Card>
119	        </GridItem>
120	      </Grid>
121	      <CreateVMFooter />
122	    </>
123	  );
124	};
125	
126	export default CreateFromInstanceType;

